    [TestInitialize]
    public void Setup()
    {
        _formatter = new StringFormatter();
    }

    // --- FormatPhoneNumber Tests ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("4255551234");

        StringAssert.StartsWith(result, "(425)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("4255551234");

        StringAssert.EndsWith(result, "-1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsExchange()
    {
        var result = _formatter.FormatPhoneNumber("4255551234");

        StringAssert.Contains(result, "555");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFullFormat()
    {
        var result = _formatter.FormatPhoneNumber("4255551234");

        Assert.AreEqual("(425) 555-1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber("12345"));
    }

    // --- BuildGreeting Tests ---

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_WithName_ContainsName()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.Contains(result, "Johnson");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_StartsWithDearTitle()
    {
        var result = _formatter.BuildGreeting("Jones", "Ms.");

        StringAssert.StartsWith(result, "Dear Ms.");
    }

    [TestMethod]
    public void BuildGreeting_FullResult_ReturnsExpected()
    {
        var result = _formatter.BuildGreeting("Smith", "Dr.");

        Assert.AreEqual("Dear Dr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting("   "));
    }

    // --- GenerateSlug Tests ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithPrefix_StartsWithExpected()
    {
        var result = _formatter.GenerateSlug("Getting Started with CSharp");

        StringAssert.StartsWith(result, "getting-started");
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSuffix_EndsWithExpected()
    {
        var result = _formatter.GenerateSlug("Introduction to Unit Testing");

        StringAssert.EndsWith(result, "testing");
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_ContainsOnlyValidChars()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        StringAssert.Matches(result, new Regex(@"^[a-z0-9\-]+$"));
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingSpaces_DoesNotStartWithHyphen()
    {
        var result = _formatter.GenerateSlug("  Padded Title  ");

        StringAssert.DoesNotMatch(result, new Regex(@"^-"));
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceOnly_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug("   "));
    }

    // --- FormatCurrency Tests ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimals()
    {
        var result = _formatter.FormatCurrency(100m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_WithCents_EndsWithCents()
    {
        var result = _formatter.FormatCurrency(42.50m);

        StringAssert.EndsWith(result, ".50");
    }

    [TestMethod]
    public void FormatCurrency_FullResult_ReturnsExpected()
    {
        var result = _formatter.FormatCurrency(1234.56m, "£");

        Assert.AreEqual("£1234.56", result);
    }
}

